sql:
SELECT model_name, 
       (SELECT COUNT(*) FROM training_sessions WHERE model_id = m.model_id) AS session_count
FROM models m;

external_knowledge:
- 'Architects, engineers, and master builders' refers to the model name; 
- 'Workshops' refers to the average training session duration; 
- 'Mastermind' refers to the top creator of each model, ranked by the number of training sessions they created.
